sql:
SELECT store_id, SUM(total_sales) AS total_sales
FROM sales_data
GROUP BY store_id;

external_knowledge:
- 'seasoned orchards' refers to existing stores that have been in operation before the year in question;
- 'North American garden' refers to the North American region;
- 'harvest year' signifies the specific year for which the sales are being calculated, in this case, 2022;
- 'yield' refers to the sales figures.

sql:
SELECT total_sales
FROM sales_data
ORDER BY year, month;
